#!/usr/bin/env node
/**
 * gen-atom-catalogue — encode the skill corpus as a RUNTIME atom catalogue.
 *
 * The MCP layer is Worker-bound (no filesystem), and its self-generating atom
 * (auto-generated.ts) projects spec primitives from in-memory registries. Skills
 * ARE atoms — to project them too they need a runtime registry, not a build-time
 * SKILL.md walk. This generator walks every src/**\/SKILL.md, reads its frontmatter
 * (name + description), norms the folder leaf to the atom, dedupes by atom
 * (content-addressed: one atom per name), and emits a static .ts the MCP layer
 * imports. Re-runnable (build / breath loop): `pnpm atoms:catalogue`.
 *
 *   node src/atom/catalogue.mjs
 */
import { readFileSync, readdirSync, statSync, writeFileSync } from 'node:fs'
import { join, basename, dirname, relative } from 'node:path'

const norm = (s) => String(s).toLowerCase().replace(/[-_]/g, '')
const OUT = 'src/agents/mcp/atom-catalogue.generated.ts'

function walk(dir, out = []) {
  let entries
  try {
    entries = readdirSync(dir)
  } catch {
    return out
  }
  for (const e of entries) {
    const p = join(dir, e)
    let s
    try {
      s = statSync(p)
    } catch {
      continue
    }
    if (s.isDirectory()) walk(p, out)
    else if (e === 'SKILL.md') out.push(p)
  }
  return out
}

// frontmatter: the leading --- ... --- block; pull name + description (first line, dequoted)
function frontmatter(text) {
  const m = text.match(/^---\n([\s\S]*?)\n---/)
  if (!m) return {}
  const body = m[1]
  const get = (key) => {
    const mm = body.match(new RegExp(`^${key}:\\s*(.+)$`, 'm'))
    if (!mm) return undefined
    return mm[1].trim().replace(/^["']/, '').replace(/["']$/, '').replace(/\\(["'])/g, '$1').trim()
  }
  return { name: get('name'), description: get('description') }
}

const byAtom = new Map()
for (const f of walk('src')) {
  const leaf = basename(dirname(f))
  const atom = norm(leaf)
  const { name, description } = frontmatter(readFileSync(f, 'utf8'))
  // last write wins (merge law); prefer entries that carry a description
  const prev = byAtom.get(atom)
  if (prev && prev.description && !description) continue
  byAtom.set(atom, {
    atom,
    name: name || leaf,
    description: description || '',
    path: relative('src', dirname(f)),
  })
}

const catalogue = [...byAtom.values()].sort((a, b) => a.atom.localeCompare(b.atom))

const header = `/**
 * GENERATED by src/atom/catalogue.mjs — do not edit by hand.
 *
 * The erpax skill corpus as a runtime atom registry (one entry per content-
 * addressed atom). The MCP self-generating atom (./auto-generated.ts) projects
 * each as an \`erpax.auto.skill.<atom>\` tool, so an MCP-only agent discovers +
 * invokes every skill without ever reading a .md file. Re-run: pnpm atoms:catalogue.
 *
 * @standard MCP 0.6 tools/list (skill projection)
 * @audit ISO 19011:2018 §6.4.6 (catalogue traceable to the SKILL.md corpus)
 */

export interface AtomSkill {
  /** content-addressed atom name (norm'd folder leaf) */
  readonly atom: string
  /** the skill frontmatter name */
  readonly name: string
  /** the skill frontmatter description (when-to-use) */
  readonly description: string
  /** path under src/ */
  readonly path: string
}

export const ATOM_CATALOGUE: readonly AtomSkill[] = ${JSON.stringify(catalogue, null, 2)}
`

writeFileSync(OUT, header)
console.log(`gen-atom-catalogue: ${catalogue.length} atoms → ${OUT}`)
